INSERT INTO "posts" VALUES('lab-upgrades-complete','Lab Upgrades Complete','March 05, 2026','Our engineers finally integrated the new glowing high-tech robotic arms into our test environment.','/news_2.png','[{"type":"heading","level":2,"content":"Welcoming the New Equipment"},{"type":"paragraph","content":"The lab now features fully integrated industrial robotic manipulator test stands. This provides our CAD team and programmers instant verification mechanisms for their reverse-kinematic code!"},{"type":"image","src":"/gallery_3.png","alt":"Sparking machinery"},{"type":"paragraph","content":"Safety first, but speed close second."}]',NULL,NULL);
