INSERT INTO "docs" VALUES('interactive-code-playground','Untitled','Interactive Lessons',30,NULL,'{"type":"doc","content":[{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"title: \"Interactive Code Playground\" description: \"Learn ARESLib programming patterns through interactive code examples and real-time feedback.\" sidebar: order: 15"}]},{"type":"paragraph","content":[{"type":"text","text":"The ARESLib Code Playground is an interactive learning environment where you can explore real programming patterns from championship-winning FTC robots. Experiment with swerve drive control, vision alignment, PID mechanisms, and state machines - all in your browser."}]},{"type":"interactiveComponent","attrs":{"componentName":"CodePlayground"}},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"How It Works"}]},{"type":"paragraph","content":[{"type":"text","text":"The Code Playground demonstrates production-ready ARESLib patterns used by FTC Team 2614. Each example includes:"}]},{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"Real Code"},{"type":"text","text":" - Actual patterns from competition robots, not simplified examples ✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"Best Practices"},{"type":"text","text":" - Proper Command-based programming and AdvantageKit logging ✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"Safety First"},{"type":"text","text":" - Fault handling and state management built-in ✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"Performance"},{"type":"text","text":" - Zero-allocation patterns and real-time control"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Featured Examples"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🏎️ Swerve Drive Basics"}]},{"type":"paragraph","content":[{"type":"text","text":"Learn the fundamentals of controlling a swerve drive robot using ARESLib''''s abstraction layer. This example shows:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ChassisSpeeds for robot-relative control."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Proper Command structure with requirements."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Real-time velocity control for competitive play."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"👁️ Vision Alignment"}]},{"type":"paragraph","content":[{"type":"text","text":"Explore automatic AprilTag alignment using ARESLib''''s vision system. Demonstrates:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Vision pose estimation fusion."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"PID controllers for precise positioning."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Continuous angle handling for rotation."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"⚙️ PID Elevator Control"}]},{"type":"paragraph","content":[{"type":"text","text":"Master position control with linear mechanisms. Features:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"LinearMechanismIO abstraction layer."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"PID control with feedforward for gravity compensation."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Proper periodic() update patterns."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🤖 State Machine Superstructure"}]},{"type":"paragraph","content":[{"type":"text","text":"Coordinate complex mechanisms using ARESLib state machines. Shows:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ARESStateMachine for multi-system coordination."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Safe state transitions and behaviors."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Emergency stop (E-Stop) setup."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Programming Patterns"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Command-Based structure"}]},{"type":"paragraph","content":[{"type":"text","text":"All examples follow ARESLib / FTClib''''s Command-based programming pattern:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class ExampleCommand extends Command {\n    private final Subsystem subsystem;\n\n    public ExampleCommand(Subsystem subsystem) {\n        this.subsystem = subsystem;\n        addRequirements(subsystem);  // Declare requirements\n    }\n\n    @Override\n    public void execute() {\n        // Control logic here\n    }\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"IO Abstraction Layer"}]},{"type":"paragraph","content":[{"type":"text","text":"ARESLib separates logic from hardware through interfaces:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Your subsystem logic works with any IO implementation\npublic class MechanismSubsystem extends Subsystem {\n    private final MechanismIO io;  // Can be Real or Sim\n\n    @Override\n    public void periodic() {\n        // Works the same on robot and in simulation!\n        double position = io.getPosition();\n    }\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"AdvantageKit Integration"}]},{"type":"paragraph","content":[{"type":"text","text":"All subsystems automatically log state for AdvantageScope:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// ARESLib handles logging automatically\n// No manual logging code needed in your subsystems\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Best Practices"}]},{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"DO"},{"type":"text","text":" use Command-based programming for autonomous and teleop ✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"DO"},{"type":"text","text":" use ARESLib''''s IO abstractions for hardware independence ✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"DO"},{"type":"text","text":" use state machines for complex mechanism coordination ✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"DO"},{"type":"text","text":" tune PID gains using SysId characterization ✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"DO"},{"type":"text","text":" implement safety mechanisms (E-Stop, limits)"}]},{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"DON''''T"},{"type":"text","text":" put hardware-specific code in your commands ❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"DON''''T"},{"type":"text","text":" ignore feedback from sensors ❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"DON''''T"},{"type":"text","text":" skip proper requirement management ❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"DON''''T"},{"type":"text","text":" forget about fault tolerance ❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"DON''''T"},{"type":"text","text":" block in execute() methods"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Next Steps"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Explore More Examples"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Check out the "},{"type":"text","marks":[{"type":"link","attrs":{"href":"/framework-structure/state-machines","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"State Machine tutorial"},{"type":"text","text":" for advanced coordination."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Learn about "},{"type":"text","marks":[{"type":"link","attrs":{"href":"/subsystems/vision","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"Vision Systems"},{"type":"text","text":" for AprilTag integration."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Study "},{"type":"text","marks":[{"type":"link","attrs":{"href":"/subsystems/swerve","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"Swerve Drive"},{"type":"text","text":" for autonomous path following."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Practice on Your Own"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Clone the ARESLib repository"},{"type":"text","text":" and explore the full codebase."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Run the simulator"},{"type":"text","text":" to see these patterns in action."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Modify the examples"},{"type":"text","text":" to learn by experimentation."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Build your own mechanisms"},{"type":"text","text":" using ARESLib patterns."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Join the Community"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"GitHub"},{"type":"text","text":": "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://github.com/ARESProgramming/ARESLib","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"ARESProgramming/ARESLib"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Documentation"},{"type":"text","text":": "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://ARESProgramming.github.io/ARESLib/","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"ARESProgramming.github.io/ARESLib"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Team"},{"type":"text","text":": FTC 2614 - Appalachian Area RoboticS."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Technical Details"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Supported Patterns"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ Command-based programming."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ State machines with ARESStateMachine."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ Vision-based alignment using ARESVision."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ PID control with feedforward."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ Swerve drive kinematics."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ Mechanism coordination."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"structure Alignment"}]},{"type":"paragraph","content":[{"type":"text","text":"All examples follow ARESLib''''s core structure:"}]},{"type":"interactiveComponent","attrs":{"componentName":"Mermaid"}},{"type":"paragraph","content":[{"type":"text","text":" B[\"Subsystem\"] B B[\"Subsystem\"] B --> C[\"IO Interface\"] C C[\"IO Interface\"] C --> D[\"IOReal (Hardware)\"] C D[\"IOReal (Hardware)\"] C --> E[\"IOSim (Physics)\"] B E[\"IOSim (Physics)\"] B --> F[\"AdvantageKit Log\"] style A fill:#1a1a1a,stroke:#B32416,stroke-width:2px,color:#fff style B fill:#1a1a1a,stroke:#B32416,stroke-width:2px,color:#fff style C fill:#B32416,stroke:#d42e1e,stroke-width:2px,color:#fff style D fill:#2a2a2a,stroke:#1a1a1a,stroke-width:1px,color:#29b6f6 style E fill:#2a2a2a,stroke:#1a1a1a,stroke-width:1px,color:#9c7bcc style F fill:#0a0a0a,stroke:#6ba3d6,stroke-width:2px,color:#6ba3d6 `} />"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"📖 Further Reading & External Resources"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"https://docs.wpilib.org/en/stable/docs/software/commandbased/what-is-command-based.html","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"ARESLib / FTClib Command-Based Programming"},{"type":"text","text":" - Official ARESLib / FTClib guide to Command-based programming."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"https://docs.advantagekit.org/","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"AdvantageKit Documentation"},{"type":"text","text":" - Learn about the logging framework that powers ARESLib."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"https://docs.wpilib.org/en/stable/docs/software/wpilib-tools/robot-characterization/introduction.html","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"SysId Characterization"},{"type":"text","text":" - Tool for PID tuning and system identification."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"link","attrs":{"href":"https://docs.photonvision.org/","target":"_blank","rel":"noopener noreferrer nofollow","class":null,"title":null}}],"text":"PhotonVision Documentation"},{"type":"text","text":" - AprilTag detection and vision processing."}]}]}]}]}','2026-04-18 16:20:27');
INSERT INTO "docs" VALUES('troubleshooting-hardware-bus','Untitled','Operations & Troubleshooting',50,NULL,'{"type":"doc","content":[{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"title: \"CAN Bus - Troubleshooting Guide\" description: \"Fix CAN bus communication problems, motor errors, and connection issues.\" sidebar: order: 4"}]},{"type":"paragraph","content":[{"type":"text","text":"CAN bus problems can make your robot behave strangely or not work at all. This guide helps you find and fix CAN issues fast."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"What is CAN Bus?"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"CAN Bus"},{"type":"text","text":" = Controller Area Network bus"}]},{"type":"paragraph","content":[{"type":"text","text":"It''''s like a conversation where robot parts take turns talking on a shared wire. Instead of each device having its own wires, they all share one communication line."}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Think of it like"},{"type":"text","text":": A classroom where students raise their hands to speak. Only one person talks at a time, so everyone can understand."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Quick Check (2 minutes)"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"1 Check CAN Status"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"In Phoenix Tuner"},{"type":"text","text":" (for REV devices):"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Open Phoenix Tuner."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Look at the top bar."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Check \"CAN Bus Utilization\" ."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Check \"CAN Bus Status\"."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What you want to see"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"Utilization"},{"type":"text","text":": Under 80% (ideally under 60%)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"Status"},{"type":"text","text":": \"OK\" or \"Connected\"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"Devices"},{"type":"text","text":": All your devices listed."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"What indicates problems"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"Utilization"},{"type":"text","text":": Over 80% (bus is congested)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"Status"},{"type":"text","text":": \"BUS OFF\" or \"Disconnected\"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"Devices"},{"type":"text","text":": Missing devices or red X''''s."}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"In OutlineViewer/SmartDashboard"},{"type":"text","text":":"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"typ