INSERT INTO "docs" VALUES('troubleshooting-robot-wont-move','Untitled','Operations & Troubleshooting',40,NULL,'{"type":"doc","content":[{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"title: \"Robot Won''''t Move - Troubleshooting Guide\" description: \"Step-by-step checklist to diagnose and fix why your robot won''''t move.\" sidebar: order: 1"}]},{"type":"paragraph","content":[{"type":"text","text":"Every technical hurdle is an opportunity for "},{"type":"text","marks":[{"type":"bold"}],"text":"Discovery"},{"type":"text","text":". If your robot isn''''t moving as expected, don''''t panic—this is where your team''''s "},{"type":"text","marks":[{"type":"bold"}],"text":"Innovation"},{"type":"text","text":" and "},{"type":"text","marks":[{"type":"bold"}],"text":"Teamwork"},{"type":"text","text":" shine. Follow this checklist to systematically diagnose the issue, turning a stressful moment into a "},{"type":"text","marks":[{"type":"bold"}],"text":"Fun"},{"type":"text","text":" learning experience and ensuring your robot makes its next high-"},{"type":"text","marks":[{"type":"bold"}],"text":"Impact"},{"type":"text","text":" appearance on the field."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Quick Check (30 seconds)"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"1. Is Robot Code Running?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Look at the Driver Station."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Is \"Robot Code\" showing "},{"type":"text","marks":[{"type":"bold"}],"text":"GREEN"},{"type":"text","text":"?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"❌ "},{"type":"text","marks":[{"type":"bold"}],"text":"RED/YELLOW"},{"type":"text","text":": Code isn''''t running."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ "},{"type":"text","marks":[{"type":"bold"}],"text":"GREEN"},{"type":"text","text":": Code is running, skip to Step 2."}]}]}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"If not green:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Check for errors in RioLog."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Reboot the Control Hub."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Restart the Driver Station."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Redeploy code if needed."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2. Is Robot Enabled?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Look at Driver Station mode."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Are you in "},{"type":"text","marks":[{"type":"bold"}],"text":"Teleop"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"bold"}],"text":"Auto"},{"type":"text","text":", or "},{"type":"text","marks":[{"type":"bold"}],"text":"Test"},{"type":"text","text":" mode?"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Is the "},{"type":"text","marks":[{"type":"bold"}],"text":"ENABLE"},{"type":"text","text":" button pressed?"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"If disabled:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Click the mode you want (usually Teleop)"}]}]},{"type":"listItem","content":[{"type":"parag